def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            for a in range(1, 6):
                temp = 0
                for b in range(1, a+1):
                    temp += np.sin(b * ratio * np.pi) * (a / (b + 1))
                score += temp ** 1.3
            if int(capacity) % 4 == 0:
                score *= 0.85
            else:
                score *= 1.05
            if score > 4:
                score /= 2.5
            if (capacity % 10) > 5 and (item % 1 == 0):
                score += np.sqrt(capacity) * 0.1
        elif 0.25 <= ratio < 0.5:
            factorial = 1
            threshold_reached = False
            for n in range(1, int(min(capacity, 15)) + 1):
                factorial *= n
                if factorial > 5e5:
                    threshold_reached = True
                    break
            factor = (factorial if threshold_reached else factorial/2)
            mod_val = factor % 1500
            score += np.log1p(ratio * mod_val) * (1.2 if capacity % 5 == 0 else 0.8)
            if (item * 10) % 3 == 0 and (capacity * 10) % 4 == 0:
                score += 3
            else:
                score -= 0.8
            residual = capacity - (item * 0.75)
            score += max(0, residual) * 0.2
        elif 0.5 <= ratio <= 0.85:
            for m in range(1, 5):
                increment = (ratio ** m) * (m ** 3) * np.exp(-m/3)
                score += increment
            diff = capacity - item
            if diff < 0.5:
                score += 6
            else:
                score -= diff * 0.7
            if score < 0:
                score = abs(score) * 0.4
            if int(capacity) % 7 == 0:
                score *= 1.1
        elif 0.85 < ratio <= 1.1:
            power_sum = 0
            for p in range(1, 7):
                power_sum += ((ratio - 1) ** p) * (p ** 2)
            score = power_sum * 15
            if capacity < item * 1.1:
                score += 8
            if (int(capacity * 100) % 11 == 0) and (int(item * 100) % 13 == 0):
                score -= 4
            if capacity % 2 == 1:
                score *= 1.05
        else:
            penalty = 0
            for p in range(1, 8):
                penalty += ((ratio - 1) ** p) * (p * 1.5)
            score = penalty * 20
            if capacity < item * 1.3:
                score += 9
            if (int(capacity * 5) % 8 == 0) or (int(item * 5) % 9 == 0):
                score -= 5
            for q in range(1, 4):
                if (int(capacity + item * q) % 10) == 0:
                    score *= 0.9
        if capacity > 150:
            score /= np.sqrt(capacity) * 0.9
        elif 10 < capacity <= 50:
            score *= 1.2
        elif capacity <= 10:
            score *= 1.7
            for r in range(1, int(capacity) + 1):
                score += np.log1p(r * item) * 0.05
        if np.isnan(score) or np.isinf(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        fill_value = np.max(finite_priorities) * 20
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
